urlset:
{{ site_base_url }}{% url 'home' %}
{{ site_base_url }}{% url 'discover' %}
{{ site_base_url }}{% url 'community' %}
{{ site_base_url }}{% url 'charts' %}
{{ site_base_url }}{% url 'artists' %}
{{ site_base_url }}{% url 'albums' %}
{{ site_base_url }}{% url 'categories' %}
{{ site_base_url }}{% url 'playlists' %}
{{ site_base_url }}{% url 'legal_pages' %}
{% for archive in search_archives %}
  {{ site_base_url }}{{ archive.url }}
{% endfor %}
{% for track in tracks %}
  {{ site_base_url }}{% url 'track_detail' track.id %}{{ track.updated_at|date:"Y-m-d" }}
{% endfor %}
{% for artist in artists %}
  {{ site_base_url }}{% url 'artist_detail' artist.id %}
{% endfor %}
{% for album in albums %}
  {{ site_base_url }}{% url 'album_detail' album.id %}
{% endfor %}
{% for page in legal_pages %}
  {{ site_base_url }}{% url 'legal_page_detail' page.slug %}{{ page.updated_at|date:"Y-m-d" }}
{% endfor %}
{% for comment in track_comments %}
  {{ site_base_url }}{% url 'track_comment_detail' comment.id %}{{ comment.created_at|date:"Y-m-d" }}
{% endfor %}
{% for comment in post_comments %}
  {{ site_base_url }}{% url 'post_comment_detail' comment.id %}{{ comment.created_at|date:"Y-m-d" }}
{% endfor %}
